mapper.select:
/*	설	명	: 강의(주차)일정목록조회, 강의일정목록조회, 강의주차일정목록조회	*/		
SELECT 	*
FROM	TB_LMS_LCTR_WKNO_SCHDL
WHERE 	SBJCT_ID = #{subjectId}

/*	설  명	: 교수강의일정목록조회		*/
SELECT	*
FROM	TB_LMS_LCTR_WKNO_SCHDL
WHERE 	SBJCT_ID = #{subjectId}

mapper.update:
/*
	 SQL ID : LectureScheduleDAO.wknoSchdlForPlandocModify
	 설  명  : 주차별강의일정 수정 - 강의계획서용
*/
UPDATE TB_LMS_LCTR_WKNO_SCHDL
SET
    LCTR_TYCD = #{lctrTycd}
	, LCTR_TTL  = #{lctrTtl}
	, LCTR_CTS  = #{lctrCts}
	, MDFR_ID   = #{mdfrId}
	, MOD_DTTM  = FN_DTTM()
WHERE LCTR_WKNO_SCHDL_ID = #{lctrWknoSchdlId}
